//! CRAP-metric gate via [`cargo-crap`](https://crates.io/crates/cargo-crap).
//!
//! Powers `cargo xcrap` and the `crap` CI step. The CRAP score
//! (`complexity² · (1 − coverage)³ + complexity`) flags functions that are both
//! cyclomatically complex and poorly covered — the highest-risk code to modify.
//! The gate reads the merged `lcov.info` that the `coverage` step already
//! produces, so it never recompiles: it only parses source and the lcov report.

use std::{
    fmt::{self, Display},
    io,
    path::{Path, PathBuf},
    process::{self, Stdio},
};

/// Pinned `cargo-crap` version — keep in sync with `.github/workflows/ci.yml`
/// and the CLAUDE.md note. Pinning is deliberate: cargo-crap's scoring and
/// mutators can change between releases, and an unpinned install would silently
/// shift the gate without a code change.
pub const CARGO_CRAP_VERSION: &str = "0.2.2";

/// CRAP score above which a function fails the gate. Matches cargo-crap's
/// built-in default and the canonical Crap4J cutoff: lenient on well-covered
/// code (full coverage tolerates complexity up to this value), strict on
/// complex-but-untested code.
pub const CRAP_THRESHOLD: u32 = 30;

/// Files skipped at walk time (`--exclude`). Every entry must carry a
/// justification so the gate's blind spots stay auditable.
const EXCLUDE_GLOBS: &[&str] = &[
    // `ars-derive` is a proc-macro crate: its code runs inside the compiler, so
    // `cargo-llvm-cov` never instruments it. Every function would otherwise be
    // scored at 0% coverage (`--missing pessimistic`), exploding CRAP for code
    // the coverage gate deliberately does not measure. It is exercised via
    // `crates/ars-core/tests/derive_contract.rs`.
    "crates/ars-derive/**",
    // Build artifacts and generated output — never first-party code under test.
    "target/**",
];

/// Functions suppressed from the report (`--allow`). Every entry must carry a
/// justification. Prefer adding tests (which lowers the coverage-driven CRAP
/// score) over adding an entry here.
const ALLOW_GLOBS: &[&str] = &[];

/// Output format for the CRAP report.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Format {
    /// Human-readable ranked table — used for local development.
    Human,

    /// GitHub Actions workflow commands (`::warning` per crappy function) —
    /// used in CI so offenders surface as PR annotations.
    Github,
}

impl Format {
    /// The `--format` argument value cargo-crap expects.
    const fn as_arg(self) -> &'static str {
        match self {
            Self::Human => "human",
            Self::Github => "github",
        }
    }
}

/// Selects the report format from the `GITHUB_ACTIONS` environment variable,
/// which GitHub Actions sets to `true` inside a workflow run.
#[must_use]
pub fn format_for_env() -> Format {
    format_from_ci_flag(std::env::var("GITHUB_ACTIONS").ok().as_deref())
}

/// Maps the raw `GITHUB_ACTIONS` value to a [`Format`]. Split out from
/// [`format_for_env`] so it is testable without mutating process environment.
fn format_from_ci_flag(github_actions: Option<&str>) -> Format {
    match github_actions {
        Some("true") => Format::Github,
        _ => Format::Human,
    }
}

/// Options for a CRAP gate run.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Options {
    /// Path to the merged lcov report (typically `lcov.info` at the repo root).
    pub lcov: PathBuf,

    /// CRAP score threshold forwarded as `--threshold`.
    pub threshold: u32,

    /// When `true`, pass `--fail-above` so the process exits non-zero if any
    /// function exceeds [`Options::threshold`].
    pub fail_above: bool,

    /// Report output format.
    pub format: Format,
}

/// Errors returned by the CRAP gate.
#[derive(Debug)]
pub enum Error {
    /// `cargo-crap` is not installed or not on `PATH`.
    MissingTool {
        /// Human-readable tool name.
        tool: String,

        /// Suggested install command.
        install_hint: String,
    },

    /// The lcov coverage report does not exist.
    MissingLcov {
        /// The path that was expected to hold the report.
        path: PathBuf,
    },

    /// The subprocess exited unsuccessfully (a threshold breach under
    /// `--fail-above`, or a cargo-crap error).
    CommandFailed {
        /// Exit code, if available.
        code: Option<i32>,
    },

    /// IO error while spawning the subprocess.
    Io(io::Error),
}

impl Display for Error {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::MissingTool { tool, install_hint } => {
                write!(
                    f,
                    "missing required tool: {tool}\n  install: {install_hint}"
                )
            }

            Self::MissingLcov { path } => {
                write!(
                    f,
                    "coverage report not found: {}\n  run `cargo xci coverage` first to generate it",
                    path.display()
                )
            }

            Self::CommandFailed { code } => {
                write!(f, "cargo crap failed")?;

                if let Some(code) = code {
                    write!(f, " (exit {code})")?;
                }

                Ok(())
            }

            Self::Io(err) => err.fmt(f),
        }
    }
}

impl From<io::Error> for Error {
    fn from(value: io::Error) -> Self {
        Self::Io(value)
    }
}

/// Builds the `cargo crap …` argument vector for `options`.
///
/// The leading `"crap"` is the subcommand name cargo injects when a binary is
/// invoked as `cargo crap`; cargo-crap tolerates it. Split out as a pure
/// function so the argument surface is unit-testable.
fn build_args(options: &Options) -> Vec<String> {
    let mut args = vec![
        "crap".to_owned(),
        "--workspace".to_owned(),
        "--lcov".to_owned(),
        options.lcov.display().to_string(),
        "--threshold".to_owned(),
        options.threshold.to_string(),
        "--format".to_owned(),
        options.format.as_arg().to_owned(),
    ];

    if options.fail_above {
        args.push("--fail-above".to_owned());
    }

    for glob in EXCLUDE_GLOBS {
        args.push("--exclude".to_owned());
        args.push((*glob).to_owned());
    }

    for glob in ALLOW_GLOBS {
        args.push("--allow".to_owned());
        args.push((*glob).to_owned());
    }

    args
}

/// Runs the CRAP gate.
///
/// # Errors
///
/// Returns [`Error::MissingTool`] when `cargo-crap` is unavailable,
/// [`Error::MissingLcov`] when the coverage report is absent,
/// [`Error::CommandFailed`] when the subprocess exits non-zero (including a
/// threshold breach under `--fail-above`), or [`Error::Io`] on spawn failures.
pub fn run(options: &Options) -> Result<(), Error> {
    preflight_cargo_crap()?;
    preflight_lcov(&options.lcov)?;

    let args = build_args(options);

    eprintln!("  > cargo {}", args.join(" "));

    let status = process::Command::new("cargo")
        .args(&args)
        .stdin(Stdio::inherit())
        .stdout(Stdio::inherit())
        .stderr(Stdio::inherit())
        .status()?;

    if status.success() {
        Ok(())
    } else {
        Err(Error::CommandFailed {
            code: status.code(),
        })
    }
}

fn preflight_cargo_crap() -> Result<(), Error> {
    let output = process::Command::new("cargo")
        .args(["crap", "--version"])
        .output()?;

    if output.status.success() {
        return Ok(());
    }

    Err(Error::MissingTool {
        tool: "cargo-crap".into(),
        install_hint: format!("cargo install cargo-crap --locked --version {CARGO_CRAP_VERSION}"),
    })
}

fn preflight_lcov(lcov: &Path) -> Result<(), Error> {
    if lcov.exists() {
        Ok(())
    } else {
        Err(Error::MissingLcov {
            path: lcov.to_path_buf(),
        })
    }
}

