mod tests {
    use super::*;

    fn options(fail_above: bool, format: Format) -> Options {
        Options {
            lcov: PathBuf::from("lcov.info"),
            threshold: CRAP_THRESHOLD,
            fail_above,
            format,
        }
    }

    /// Collect the values that follow every occurrence of `flag` in `args`.
    fn values_after<'a>(args: &'a [String], flag: &str) -> Vec<&'a str> {
        args.windows(2)
            .filter(|pair| pair[0] == flag)
            .map(|pair| pair[1].as_str())
            .collect()
    }

    #[test]
    fn cargo_crap_version_matches_ci_pin() {
        assert_eq!(CARGO_CRAP_VERSION, "0.2.2");
    }

    #[test]
    fn threshold_is_thirty() {
        assert_eq!(CRAP_THRESHOLD, 30);
    }

    #[test]
    fn build_args_starts_with_crap_subcommand_and_workspace() {
        let args = build_args(&options(true, Format::Github));

        assert_eq!(args[0], "crap");
        assert!(args.iter().any(|arg| arg == "--workspace"));
        assert_eq!(values_after(&args, "--lcov"), vec!["lcov.info"]);
    }

    #[test]
    fn build_args_carries_threshold_and_format() {
        let args = build_args(&options(false, Format::Human));

        assert_eq!(values_after(&args, "--threshold"), vec!["30"]);
        assert_eq!(values_after(&args, "--format"), vec!["human"]);
    }

    #[test]
    fn build_args_toggles_fail_above() {
        assert!(
            build_args(&options(true, Format::Github))
                .iter()
                .any(|arg| arg == "--fail-above")
        );

        assert!(
            !build_args(&options(false, Format::Github))
                .iter()
                .any(|arg| arg == "--fail-above")
        );
    }

    #[test]
    fn build_args_forwards_every_exclude_and_allow_glob() {
        let args = build_args(&options(true, Format::Github));

        let excludes = values_after(&args, "--exclude");
        for glob in EXCLUDE_GLOBS {
            assert!(excludes.contains(glob), "missing --exclude {glob}");
        }
        assert_eq!(excludes.len(), EXCLUDE_GLOBS.len());

        let allows = values_after(&args, "--allow");
        for glob in ALLOW_GLOBS {
            assert!(allows.contains(glob), "missing --allow {glob}");
        }
        assert_eq!(allows.len(), ALLOW_GLOBS.len());
    }

    #[test]
    fn exclude_globs_skip_unmeasured_proc_macro_crate() {
        assert!(
            EXCLUDE_GLOBS.contains(&"crates/ars-derive/**"),
            "ars-derive is unmeasured by llvm-cov and must be excluded"
        );
    }

    #[test]
    fn format_from_ci_flag_maps_github_actions_true() {
        assert_eq!(format_from_ci_flag(Some("true")), Format::Github);
        assert_eq!(format_from_ci_flag(Some("false")), Format::Human);
        assert_eq!(format_from_ci_flag(None), Format::Human);
    }

    #[test]
    fn format_as_arg_round_trips() {
        assert_eq!(Format::Human.as_arg(), "human");
        assert_eq!(Format::Github.as_arg(), "github");
    }
}

