/// [`native_thresholds`]. Passed as `-p` flags to scope the instrumented run.
#[must_use]
pub fn native_coverage_packages() -> Vec<String> {
    native_thresholds()
        .into_iter()
        .map(|threshold| threshold.package)
        .collect()
}

